import { NodeModel } from './nodemodel';
import { Nodeshape } from './nodeshape.enum';

export class Nodeviewmodel {

    x: number;
    y: number;
    width: number;
    height: number;
    shape: Nodeshape;
    color: string;

    selected: boolean;
    dragged: boolean;

    constructor(x: number, y: number, width: number, height: number, shape: Nodeshape = Nodeshape.RECTANGLE, color: string = "black") {
        this.x = x;
        this.y = y;
        this.width = width;
        this.height = height;
        this.shape = shape;
        this.color = color;
        this.dragged = false;
        this.selected = false;
    }

    
}
