import { Injectable } from '@angular/core';
import { BehaviorSubject } from 'rxjs';
import { Mapmodel } from '../model/mapmodel';

@Injectable({
    providedIn: 'root',
})
export class BreadCrumService {

    private breadCrumSource = new BehaviorSubject(null);
    breadCrums = this.breadCrumSource.asObservable();

    constructor() { }

    changeBreadCrums(mapList: Mapmodel[]) {
        console.log("breadcrums changed to " + mapList.length);
        this.breadCrumSource.next(mapList);
    }
}
