import { NodeModel } from '../model/nodemodel';
import { Nodeeventlistener } from './nodeeventlistener';
import { RedrawListener } from './redraw-listener';

export class Eventhandlingcenter {
    static nodeEventListeners: Nodeeventlistener[] = [];
    // static connectionEventListeners: Connectioneventlistener[] = [];
    private static redrawListeners: RedrawListener[] = [];

    static addRedrawEventListener(listener: RedrawListener) {
        this.redrawListeners.push(listener);
    }

    static removeRedrawEventListener(listener: RedrawListener) {
        this.redrawListeners.splice(this.redrawListeners.indexOf(listener), 1);
    }

    static fireRedrawEvent() {
        console.log("fire redraw event on listeners");
        Eventhandlingcenter.redrawListeners.forEach(element => {
            element.redraw();
        });
    }

    static addNodeeventlistener(listener: Nodeeventlistener) {
        this.nodeEventListeners.push(listener);
    }

    static removeNodeeventlistener(listener: Nodeeventlistener) {
        this.nodeEventListeners.splice(this.nodeEventListeners.indexOf(listener), 1);
    }

    static nodeEvent(node: NodeModel)
    {
        this.nodeEventListeners.forEach(listener => {
            listener.nodeTextChange(node);
        });
    }
}
