import { Injectable } from '@angular/core';
import { Gobackuplistener } from './gobackuplistener';

@Injectable({
    providedIn: 'root',
}) export class MapNavigationService {

    goUpListeners: Gobackuplistener[];

    constructor() {
        this.goUpListeners = [];
    }

    public goBackUpTo(i:number) {
        this.goUpListeners.forEach(element => {
            element.goBackUpTo(i);
        });
    }
}
