import { Component, OnInit } from '@angular/core';
import { Mapmodel } from '../model/mapmodel';
import { BreadCrumService } from '../shared/bread-crum-service';
import { MapNavigationService } from '../shared/map-navigation-service';
import { Mappersistenceservice } from '../shared/mappersistenceservice';

@Component({
  selector: 'mm-menubar',
  templateUrl: './menubar.component.html',
  styleUrls: ['./menubar.component.css']
})
export class MenubarComponent implements OnInit {

  persistenceService: Mappersistenceservice;
  navigationService: MapNavigationService;
  breadCrumService: BreadCrumService;
  testText:string="test"

  breadCrumList: Mapmodel[] = [];


  constructor(persistenceService: Mappersistenceservice, navigationService: MapNavigationService, breadCrumService: BreadCrumService) {
    this.persistenceService=persistenceService;
    this.navigationService=navigationService;
    this.breadCrumService=breadCrumService;
    this.breadCrumService.breadCrums.subscribe(breadCrums=>this.setUpBreadCrums(breadCrums))
   }

  ngOnInit(): void {
  }

  selectBreadCrum(i:number)
  {
    this.navigationService.goBackUpTo(i);
  }

  setUpBreadCrums(breadCrums:Mapmodel[])
  {
    this.breadCrumList=breadCrums;
  }

  public clear()
  {
    this.persistenceService.clearAll();
  }

  public saveMap(){
    // console.log("saving map button pressed");
    this.persistenceService.save();
  }

  public loadMap(){
    // console.log("loading map button pressed");
    this.persistenceService.load();
  }
}
